Para implementar una variable de condición en C++, puedes utilizar `std::condition_variable` junto con `std::mutex`. Aquí tienes un ejemplo simple que muestra cómo coordinar la producción y el consumo de elementos utilizando estas herramientas:

```cpp
#include <iostream>
#include <thread>
#include <queue>
#include <mutex>
#include <condition_variable>

std::queue<int> buffer;
std::mutex mtx;
std::condition_variable cond_var;
bool done = false;

void producer(int id, int num_items) {
    for (int i = 0; i < num_items; ++i) {
        std::unique_lock<std::mutex> lock(mtx);
        buffer.push(i);
        std::cout << "Producer " << id << " produced: " << i << std::endl;
        cond_var.notify_one();
    }
}

void consumer(int id, int num_items) {
    for (int i = 0; i < num_items; ++i) {
        std::unique_lock<std::mutex> lock(mtx);
        while (buffer.empty() && !done) {
            cond_var.wait(lock);
        }
        if (!buffer.empty()) {
            int item = buffer.front();
            buffer.pop();
            std::cout << "Consumer " << id << " consumed: " << item << std::endl;
        }
    }
}

int main() {
    const int num_producers = 2;
    const int num_consumers = 3;
    const int items_per_producer = 5;

    std::thread producers[num_producers];
    for (int i = 0; i < num_producers; ++i) {
        producers[i] = std::thread(producer, i, items_per_producer);
    }

    std::thread consumers[num_consumers];
    for (int i = 0; i < num_consumers; ++i) {
        consumers[i] = std::thread(consumer, i, items_per_producer);
    }

    for (auto &p : producers) {
        p.join();
    }
    done = true;
    cond_var.notify_all();

    for (auto &c : consumers) {
        c.join();
    }

    return 0;
}
```
Este código muestra cómo un productor produce elementos y los coloca en un búfer compartido, mientras que los consumidores esperan a que haya elementos disponibles para consumir. El `std::condition_variable` se utiliza para sincronizar el acceso al búfer entre los hilos.

